    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 2) ROLES
CREATE TABLE roles (
    role_id SERIAL PRIMARY KEY,
    role_name VARCHAR(100) UNIQUE NOT NULL,
    description TEXT,
    is_admin_role BOOLEAN DEFAULT FALSE
);

-- 3) EMPLOYEES
CREATE TABLE employees (
    employee_id SERIAL PRIMARY KEY,
    employee_code VARCHAR(20) UNIQUE NOT NULL,
    first_name VARCHAR(50) NOT NULL,
    last_name VARCHAR(50) NOT NULL,
    email VARCHAR(100) UNIQUE NOT NULL,
    phone VARCHAR(30),
    department_id INTEGER REFERENCES departments(department_id),
    role_id INTEGER REFERENCES roles(role_id),
    manager_id INTEGER REFERENCES employees(employee_id),
    hire_date DATE,
    employment_status VARCHAR(20) DEFAULT 'Active',
    basic_salary DECIMAL(12, 2),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 4) PAYROLL_RUNS
CREATE TABLE payroll_runs (
    payroll_run_id SERIAL PRIMARY KEY,
    period_start DATE NOT NULL,
    period_end DATE NOT NULL,
    processed_on TIMESTAMP,
    status VARCHAR(20) DEFAULT 'Draft',
    processed_by INTEGER REFERENCES employees(employee_id)
);

-- 5) PAYROLL_ITEMS
CREATE TABLE payroll_items (
    payroll_item_id SERIAL PRIMARY KEY,
    payroll_run_id INTEGER REFERENCES payroll_runs(payroll_run_id),
    employee_id INTEGER REFERENCES employees(employee_id),
    base_pay DECIMAL(12, 2),
    allowance DECIMAL(12, 2),
    overtime_pay DECIMAL(12, 2),
    tax_deducted DECIMAL(12, 2),
    other_deductions DECIMAL(12, 2),
    net_pay DECIMAL(12, 2),
    UNIQUE(payroll_run_id, employee_id)
);

-- 6) CUSTOMERS
CREATE TABLE customers (
    customer_id SERIAL PRIMARY KEY,
    customer_code VARCHAR(20) UNIQUE NOT NULL,
    name VARCHAR(200) NOT NULL,
    email VARCHAR(100),
    phone VARCHAR(30),
    billing_address TEXT,
    shipping_address TEXT,
    tax_id VARCHAR(50),
    status VARCHAR(20) DEFAULT 'Active',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 7) PRODUCTS
CREATE TABLE products (
    product_id SERIAL PRIMARY KEY,
    sku VARCHAR(50) UNIQUE NOT NULL,
    name VARCHAR(200) NOT NULL,
    category VARCHAR(100),
    unit_price DECIMAL(12, 2),
    tax_rate DECIMAL(5, 4),
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 8) SALES_ORDERS
CREATE TABLE sales_orders (
    sales_order_id SERIAL PRIMARY KEY,
    order_number VARCHAR(50) UNIQUE NOT NULL,
    customer_id INTEGER REFERENCES customers(customer_id),
    order_date DATE,
    status VARCHAR(20) DEFAULT 'Draft',
    created_by INTEGER REFERENCES employees(employee_id),
    approved_by INTEGER REFERENCES employees(employee_id),
    notes TEXT
);

-- 9) SALES_ORDER_ITEMS
CREATE TABLE sales_order_items (
    sales_order_item_id SERIAL PRIMARY KEY,
    sales_order_id INTEGER REFERENCES sales_orders(sales_order_id),
    product_id INTEGER REFERENCES products(product_id),
    quantity INTEGER NOT NULL,
    unit_price_at_sale DECIMAL(12, 2),
    discount_amount DECIMAL(12, 2) DEFAULT 0,
    line_total DECIMAL(12, 2)
);

-- 10) INVOICES
CREATE TABLE invoices (
    invoice_id SERIAL PRIMARY KEY,
    invoice_number VARCHAR(50) UNIQUE NOT NULL,
    sales_order_id INTEGER REFERENCES sales_orders(sales_order_id),
    customer_id INTEGER REFERENCES customers(customer_id),
    issued_date DATE,
    due_date DATE,
    status VARCHAR(20) DEFAULT 'Unpaid',
    subtotal DECIMAL(12, 2),
    tax_total DECIMAL(12, 2),
    total_amount DECIMAL(12, 2),
    created_by INTEGER REFERENCES employees(employee_id)
);

